import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"PAM Overview","description":"","frontmatter":{"title":"PAM Overview","slug":"predictive-aggregate-measurement"},"headers":[],"relativePath":"marketer-hub/predictive-aggregate-measurement.md","filePath":"marketer-hub/predictive-aggregate-measurement.md"}'),o={name:"marketer-hub/predictive-aggregate-measurement.md"};function n(s,e,l,h,d,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Measuring attribution is becoming increasingly challenging and complex. As the privacy landscape evolves, shifting guidelines and regulations become more and more difficult to keep up with. As these rules grow and change, attribution solutions are becoming more intricate and harder to maintain.</p><p>On top of all this, there is a growing number of opted-out users in marketing programs, lowering the accuracy of campaign performance measurements. This leaves you guessing as to how to optimize user engagement, especially among iOS users.</p><h2 id="what-is-pam" tabindex="-1">What is PAM? <a class="header-anchor" href="#what-is-pam" aria-label="Permalink to &quot;What is PAM?&quot;">​</a></h2><p><strong>Predictive Aggregate Measurement (PAM)</strong> is an innovative approach to mobile campaign attribution, designed for performance marketers navigating today’s complex, privacy-focused mobile measurement world.</p><p>PAM is designed to navigate the complexities of today&#39;s changing privacy landscape while still expanding attribution coverage.</p><p>With PAM, you can <strong>unlock additional insights for users previously marked as either</strong> <code>Unattributed</code> <strong>or</strong> <code>reported under SKAN</code>.</p><p>By utilizing our predictive modeling tools alongside strict privacy protocols, PAM helps safeguard user privacy while also providing marketers with the most granular and effective reporting methodology available for each unique situation.</p><p>Our dynamic models adjust to the data available, employing the most precise attribution methods for each situation. We do this with user privacy in mind, so marketers can focus on analyzing performance and optimizing their strategies.</p><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>To understand <strong>best practices</strong> related to PAM and iOS attribution in general, visit our <a href="./ios-attribution-best-practices.html">iOS Attribution Best Practices guide</a>.</p></div><h2 id="data-precautions" tabindex="-1">Data precautions <a class="header-anchor" href="#data-precautions" aria-label="Permalink to &quot;Data precautions&quot;">​</a></h2><p>PAM maximizes attribution coverage while still remaining privacy-focused.</p><p>Below are the methods PAM uses to help you meet your privacy compliance requirements.</p><h3 id="data-aggregation" tabindex="-1">Data aggregation <a class="header-anchor" href="#data-aggregation" aria-label="Permalink to &quot;Data aggregation&quot;">​</a></h3><p>To further help protect privacy, PAM aggregates campaign data, bringing individual data points into a broader dataset.</p><p>This provides a comprehensive view of campaign performance but doesn&#39;t expose data about the individual user.</p><p>The aggregated data is presented in a way that marketers can get actionable insights while still preventing user-level identification.</p><p>Together, these three data precautions help ensure that your user&#39;s privacy is respected, while still giving you valuable insights.</p><h2 id="pam-for-publishers" tabindex="-1">PAM for Publishers <a class="header-anchor" href="#pam-for-publishers" aria-label="Permalink to &quot;PAM for Publishers&quot;">​</a></h2><p>The <strong>PAM for Publishers</strong> toggle is available in the postback <a href="./basic-postback-configuration.html">configuration</a> settings for each ad partner. It’s designed to help advertisers maintain strong performance while respecting user privacy.</p><p>When enabled, this feature removes advertiser-specific user identifiers (e.g., <code>user_data_xxx</code>) from Postbacks unless the user has opted in via Apple’s App Tracking Transparency (ATT) framework. In doing so, it prioritizes identifiers provided directly by the ad partner. This ensures compliant, high-quality signals that support effective campaign optimization.</p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>Use the steps below to enable PAM at the org-level or app-level.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> of enabling PAM, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, PAM is enabled under Configuration → <a href="./attribution-page-new.html">Attribution</a>.</p></div><h4 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h4><ol><li>PAM is available with all Performance plans. See our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page for details.</li><li>Access to make changes at the org-level or app-level, depending on what level you want to enable PAM on.</li></ol><h3 id="enable-pam-at-the-org-level" tabindex="-1">Enable PAM at the org-level <a class="header-anchor" href="#enable-pam-at-the-org-level" aria-label="Permalink to &quot;Enable PAM at the org-level&quot;">​</a></h3><p>To enable PAM at the org-level:</p><ol><li><p>Go the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a> and select the org that you want to enable PAM for.</p></li><li><p>Use the left-side navigation bar to click on <strong>App Settings</strong>, which is in the <strong>Configure</strong> section.</p></li><li><p>Next, navigate to the <strong>Attribution</strong> tab. There, you will see a switch that enables PAM. Be careful! This enables PAM for the entire org.</p></li><li><p>Flip the switch to enable PAM for the org, then make sure to click <strong>Save</strong> at the bottom of the page.</p></li></ol><h3 id="enable-pam-at-the-app-level" tabindex="-1">Enable PAM at the app-level <a class="header-anchor" href="#enable-pam-at-the-app-level" aria-label="Permalink to &quot;Enable PAM at the app-level&quot;">​</a></h3><p>To enable PAM at the app-level:</p><ol><li><p>Go the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a> and choose a specific app you want to enable PAM for.</p></li><li><p>Use the left-side navigation bar to click on <strong>App Settings</strong>, which is in the <strong>Configure</strong> section.</p></li><li><p>Next, navigate to the <strong>Attribution</strong> tab.</p></li><li><p>Check to see if the switch inside the <strong>Inherit Organization Attribution Settings</strong> section is enabled. If it is, then your app is inheriting attribution settings from the org it lives under.</p><p>Decide if you still want to make PAM changes at the app-level.</p></li><li><p>Also note that the <strong>Attribution Windows</strong> section will be greyed out if your app is inheriting from org-level attribution settings.</p></li><li><p>If you&#39;ve taken note of the org-level settings and you still want to enable PAM at the app-level, flip the PAM switch and then click <strong>Save</strong> at the bottom of the page.</p></li></ol><h3 id="enable-pam-for-publishers" tabindex="-1">Enable PAM for Publishers <a class="header-anchor" href="#enable-pam-for-publishers" aria-label="Permalink to &quot;Enable PAM for Publishers&quot;">​</a></h3><p>To enable <a href="./predictive-aggregate-measurement.html#pam-for-publishers">PAM for Publishers</a>:</p><ol><li>Navigate to the <strong>Ad Partners</strong> <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">page</a> within the Branch Dashboard.</li><li>Select the relevant ad partner from the list.</li><li>Go to the <strong>Postback Config</strong> tab for that ad partner.</li><li>Enable the <strong>PAM for Publishers</strong> toggle.</li></ol><h2 id="pam-data-structures" tabindex="-1">PAM data structures <a class="header-anchor" href="#pam-data-structures" aria-label="Permalink to &quot;PAM data structures&quot;">​</a></h2><p>For detailed information about how reporting looks based on different PAM configurations, please visit our dedicated <a href="./predictive-aggregate-measurement-data-reference.html">PAM Data Reference article</a>.</p><h2 id="pam-dashboard-data" tabindex="-1">PAM dashboard data <a class="header-anchor" href="#pam-dashboard-data" aria-label="Permalink to &quot;PAM dashboard data&quot;">​</a></h2><h3 id="dimensions" tabindex="-1">Dimensions <a class="header-anchor" href="#dimensions" aria-label="Permalink to &quot;Dimensions&quot;">​</a></h3><p>There are certain dimensions that are particularly relevant to PAM. These are <code>pam enabled</code> and <code>aggregate measurement</code>.</p><p>Within the Branch Dashboard, these dimensions can be found:</p><ul><li>On the main <strong>Summary</strong> <a href="https://branch.dashboard.branch.io/" target="_blank" rel="noreferrer">page</a>, within the <strong>All Data</strong> or <strong>Ads</strong> tabs.</li><li>On the <strong>Sources</strong> <a href="https://branch.dashboard.branch.io/sources" target="_blank" rel="noreferrer">page</a>.</li><li>On the <strong>Analytics</strong> <a href="https://branch.dashboard.branch.io/ads/analytics/activity" target="_blank" rel="noreferrer">page</a>, within the <strong>Activity</strong> tab.</li></ul><h4 id="pam-enabled" tabindex="-1">PAM enabled <a class="header-anchor" href="#pam-enabled" aria-label="Permalink to &quot;PAM enabled&quot;">​</a></h4><p>This dimension identifies whether the conversion event was attributed via PAM or not.</p><p>The possible values for this dimension are:</p><ul><li><code>true</code> - when PAM was used to attribute the event.</li><li><code>false</code> or <code>unpopulated</code> - when the attribution happened via other mechanisms, the data is unattributed via PAM, or PAM was not enabled for the selected time frame.</li></ul><h4 id="aggregate-measurement" tabindex="-1">Aggregate measurement <a class="header-anchor" href="#aggregate-measurement" aria-label="Permalink to &quot;Aggregate measurement&quot;">​</a></h4><p>This dimension is used to identify events attributed via Meta AEM or gBraid.</p><p>The possible values for this dimension are:</p><ul><li><code>true</code> - when Meta AEM or gBraid was used to attribute the events.</li><li><code>false</code> or <code>unpopulated</code> - when the attribution happened via other mechanisms, the data is unattributed via aggregate methods, or aggregate measurement was not enabled for that ad partner at that time.</li></ul><h3 id="pre-built-views" tabindex="-1">Pre-built views <a class="header-anchor" href="#pre-built-views" aria-label="Permalink to &quot;Pre-built views&quot;">​</a></h3><p>Use the following URLs to for sample configurations of Branch Dashboard reports.</p><ul><li><a href="https://branch.link/qtV64c6OlPb" target="_blank" rel="noreferrer">PAM Enabled View</a><br> Compare by <code>platform</code> and <code>pam enabled</code>, where <code>feature</code> equals <code>paid advertising</code>.</li><li><a href="https://branch.link/Go7CdX8OlPb" target="_blank" rel="noreferrer">Aggregate Measurement View</a><br> Compare by <code>platform</code> and <code>ad partner</code> and <code>aggregate measurement</code> , where <code>ad partner</code> equals <code>Google AdWords</code> or <code>Facebook</code>.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><ol><li><strong>What is required to implement PAM?</strong><br> Implementing PAM doesn&#39;t require any engineering resources, and is an easy lift for marketers. Simply follow <a href="./predictive-aggregate-measurement.html#implementation">these implementation steps</a> to enable PAM at the org-level or app-level with a switch.</li><li><strong>Is Branch reverting to modeled conversions?</strong><br> Modeled conversions from ad networks will flow into the attribution waterfall of PAM.</li><li><strong>How will Branch dedupe this aggregate data against the log-level owned channel data?</strong><br> PAM will utilize the deduplication logic we have with opt-in conversions and SKAN. The data will live within our Event-Level Reporting suite and be deduplicated against all other sources within our Unified View Analytics.</li><li><strong>Can you consider a conversion deterministic if you’re using an aggregate ID?</strong><br> Yes, if the aggregate ID is not individually identifying. This implies a many to one relationship, which can be pulled deterministically and referenced deterministically.</li><li><strong>Will this affect channels other than opted-out iOS users under paid ads?</strong><br> No. PAM increases visibility for opted-out iOS users under paid ads without affecting SEO measurement or other channels. Users previously marked as either <code>Unattributed</code> or <code>reported under SKAN</code> will be available for additional insights under PAM.</li></ol>',55)])])}const u=a(o,[["render",n]]);export{g as __pageData,u as default};
